import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider } from "./context/AuthContext";
import { ProtectedRoute, RoleRoute } from "./routes/Guards";
import "./auth.css";

// Auth pages
import EmployeeLogin  from "./pages/EmployeeLogin";
import CandidateLogin from "./pages/CandidateLogin";
import Unauthorized   from "./pages/Unauthorized";

// HR pages
import DashboardPage  from "./pages/hr/DashboardPage";
import FormPage       from "./pages/hr/FormPage";
import SubmissionPage from "./pages/hr/SubmissionPage";

// Employee pages
import CareersPage    from "./pages/employee/CareersPage";
import FeedbackPage   from "./pages/employee/FeedbackPage";

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <Routes>
          {/* --- Public routes --- */}
          <Route path="/login"           element={<EmployeeLogin />} />
          <Route path="/candidate/login" element={<CandidateLogin />} />
          <Route path="/unauthorized"    element={<Unauthorized />} />

          {/* --- Protected: all authenticated users --- */}
          <Route element={<ProtectedRoute />}>

            {/* Candidate-only */}
            <Route element={<RoleRoute allowed={["Candidate"]} />}>
              <Route path="/candidate/dashboard"    element={<CareersPage />} />
              <Route path="/candidate/applications" element={<CareersPage />} />
            </Route>

            {/* All internal employees */}
            <Route element={<RoleRoute allowed={["TeamMember", "TeamLeader", "HRManager", "Admin"]} />}>
              <Route path="/employee/dashboard" element={<FeedbackPage />} />
              <Route path="/employee/feedback"  element={<FeedbackPage />} />
            </Route>

            {/* Team Leader and above */}
            <Route element={<RoleRoute allowed={["TeamLeader", "HRManager", "Admin"]} />}>
              <Route path="/leader/team" element={<FeedbackPage />} />
            </Route>

            {/* HR Manager and above */}
            <Route element={<RoleRoute allowed={["HRManager", "Admin"]} />}>
              <Route path="/hr/dashboard"   element={<DashboardPage />} />
              <Route path="/hr/forms"       element={<FormPage />} />
              <Route path="/hr/submissions" element={<SubmissionPage />} />
            </Route>

            {/* Admin only */}
            <Route element={<RoleRoute allowed={["Admin"]} />}>
              <Route path="/admin/dashboard" element={<DashboardPage />} />
              <Route path="/admin/users"     element={<DashboardPage />} />
            </Route>

          </Route>

          {/* Fallback */}
          <Route path="/"  element={<Navigate to="/login" replace />} />
          <Route path="*"  element={<Navigate to="/login" replace />} />
        </Routes>
      </AuthProvider>
    </BrowserRouter>
  );
}
